 36→/// Configuration for the local LLM provider.
 37→#[derive(Debug, Clone)]
 38→pub struct LocalLlmConfig {
 39→    /// Model ID from the registry.
 40→    pub model_id: String,
 41→    /// Direct path to a model file (skips auto-download).
 42→    pub model_path: Option<PathBuf>,
 43→    /// Preferred backend (auto-detected if None).
 44→    pub backend: Option<BackendType>,
 45→    /// Context size in tokens (default: from model definition).
 46→    pub context_size: Option<u32>,
 47→    /// Number of layers to offload to GPU (GGUF only, 0 = CPU only).
 48→    pub gpu_layers: u32,
 49→    /// Sampling temperature.
 50→    pub temperature: f32,
 51→    /// Directory for caching downloaded models.
 52→    pub cache_dir: PathBuf,
 53→}
 54→
