 69→/// Local LLM provider with lazy loading.
 70→///
 71→/// Automatically selects the best backend for the current platform and
 72→/// loads the model on first use.
 73→pub struct LocalLlmProvider {
 74→    config: LocalLlmConfig,
 75→    inner: RwLock<Option<Box<dyn LocalBackend>>>,
 76→    selected_backend: RwLock<Option<BackendType>>,
 77→}
 78→
 79→impl LocalLlmProvider {
 80→    /// Create a new lazy-loading local LLM provider.
 81→    pub fn new(config: LocalLlmConfig) -> Self {
 82→        Self {
 83→            config,
 84→            inner: RwLock::new(None),
 85→            selected_backend: RwLock::new(None),
 86→        }
 87→    }
 88→
 89→    /// Get the backend type that will be (or was) used.
 90→    pub async fn backend_type(&self) -> BackendType {
 91→        if let Some(bt) = *self.selected_backend.read().await {
 92→            return bt;
 93→        }
 94→        self.config
 95→            .backend
 96→            .unwrap_or_else(backend::detect_best_backend)
 97→    }
 98→
 99→    /// Ensure the backend is loaded.
100→    async fn ensure_loaded(&self) -> Result<()> {
101→        // Fast path: check if already loaded
102→        {
103→            let guard = self.inner.read().await;
104→            if guard.is_some() {
105→                return Ok(());
106→            }
107→        }
108→
109→        // Slow path: load the backend
110→        let mut guard = self.inner.write().await;
111→
112→        // Double-check after acquiring write lock
113→        if guard.is_some() {
114→            return Ok(());
115→        }
116→
117→        let backend_type = self
118→            .config
119→            .backend
120→            .unwrap_or_else(|| backend::detect_backend_for_model(&self.config.model_id));
121→        info!(
122→            model = %self.config.model_id,
123→            backend = ?backend_type,
124→            "loading local LLM model"
125→        );
126→
127→        *self.selected_backend.write().await = Some(backend_type);
128→
129→        let backend = backend::create_backend(backend_type, &self.config).await?;
130→        *guard = Some(backend);
131→
132→        Ok(())
133→    }
134→}
