199→/// Log system info and backend availability.
200→pub fn log_system_info() {
201→    let sys = system_info::SystemInfo::detect();
202→    let tier = sys.memory_tier();
203→    let best_backend = backend::detect_best_backend();
204→
205→    info!(
206→        total_ram_gb = sys.total_ram_gb(),
207→        available_ram_gb = sys.available_ram_gb(),
208→        has_metal = sys.has_metal,
209→        has_cuda = sys.has_cuda,
210→        is_apple_silicon = sys.is_apple_silicon,
211→        tier = %tier,
212→        best_backend = ?best_backend,
213→        "local-llm system info"
214→    );
215→
216→    // Log available backends
217→    let available_backends = backend::available_backends();
218→    info!(backends = ?available_backends, "available local LLM backends");
219→
220→    // Suggest models
221→    if let Some(suggested) = models::suggest_model(tier, best_backend) {
222→        info!(
223→            model = suggested.id,
224→            display_name = suggested.display_name,
225→            backend = ?suggested.format.backend_type(),
226→            "suggested local model for your system"
227→        );
228→    }
229→}
