  1→//! Response parsing for local LLM backends.
  2→//!
  3→//! Different backends and models may output responses in different formats.
  4→//! This module provides a trait-based approach to parse raw output into
  5→//! structured responses, making it easy to add new parsers without modifying
  6→//! existing code.
  7→
  8→/// Parsed response from an LLM backend.
  9→#[derive(Debug, Clone, Default)]
 10→pub struct ParsedResponse {
 11→    /// The actual response text, cleaned of any formatting artifacts.
 12→    pub text: String,
 13→    /// Number of input/prompt tokens (if available).
 14→    pub input_tokens: Option<u32>,
 15→    /// Number of output/generation tokens (if available).
 16→    pub output_tokens: Option<u32>,
 17→}
 18→
 19→/// Trait for parsing raw LLM output into structured responses.
 20→///
 21→/// Implement this trait for different output formats (JSON, CLI decorators, etc.).
 22→pub trait ResponseParser: Send + Sync {
 23→    /// Parse raw output into a structured response.
 24→    fn parse(&self, raw: &str) -> ParsedResponse;
 25→
 26→    /// Human-readable name for this parser (for logging/debugging).
 27→    fn name(&self) -> &'static str;
 28→}
 29→
 30→// ── JSON Response Parser ─────────────────────────────────────────────────────
 31→
 32→/// Parser for JSON-formatted responses from Python API.
 33→///
 34→/// Expects format: `{"text": "...", "input_tokens": N, "output_tokens": M}`
 35→#[derive(Debug, Default)]
 36→pub struct JsonResponseParser;
 37→
 38→impl ResponseParser for JsonResponseParser {
 39→    fn name(&self) -> &'static str {
 40→        "json"
 41→    }
 42→
 43→    fn parse(&self, raw: &str) -> ParsedResponse {
 44→        // Try to parse as JSON
 45→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(raw) {
 46→            return ParsedResponse {
 47→                text: value["text"].as_str().unwrap_or("").to_string(),
 48→                input_tokens: value["input_tokens"].as_u64().map(|n| n as u32),
 49→                output_tokens: value["output_tokens"].as_u64().map(|n| n as u32),
 50→            };
 51→        }
 52→
 53→        // Fallback: return raw as text
 54→        ParsedResponse {
 55→            text: raw.trim().to_string(),
 56→            input_tokens: None,
 57→            output_tokens: None,
 58→        }
 59→    }
 60→}
 61→
 62→// ── MLX CLI Response Parser ──────────────────────────────────────────────────
 63→
 64→/// Parser for mlx_lm CLI output with `==========` delimiters.
 65→///
 66→/// The CLI outputs in this format:
 67→/// ```text
 68→/// ==========
 69→/// Response text here
 70→/// ==========
 71→/// Prompt: 346 tokens, 502.788 tokens-per-sec
 72→/// Generation: 35 tokens, 448.124 tokens-per-sec
 73→/// Peak memory: 1.042 GB
 74→/// ```
 75→#[derive(Debug, Default)]
 76→pub struct MlxCliResponseParser;
 77→
 78→impl ResponseParser for MlxCliResponseParser {
 79→    fn name(&self) -> &'static str {
 80→        "mlx-cli"
 81→    }
 82→
 83→    fn parse(&self, raw: &str) -> ParsedResponse {
 84→        let mut text = String::new();
 85→        let mut input_tokens = None;
 86→        let mut output_tokens = None;
 87→
 88→        // Split by the separator line
 89→        let parts: Vec<&str> = raw.split("==========").collect();
 90→
 91→        // The response text is between the first and second separator
 92→        if parts.len() >= 2 {
 93→            text = parts[1].trim().to_string();
 94→        }
 95→
 96→        // Parse token counts from the stats lines after the second separator
 97→        if parts.len() >= 3 {
 98→            for line in parts[2].lines() {
 99→                let line = line.trim();
100→                // "Prompt: 346 tokens, 502.788 tokens-per-sec"
101→                if let Some(tokens_part) = line.strip_prefix("Prompt:")
102→                    && let Some(tokens_str) = tokens_part.split_whitespace().next()
103→                {
104→                    input_tokens = tokens_str.parse().ok();
105→                }
106→                // "Generation: 35 tokens, 448.124 tokens-per-sec"
107→                else if let Some(tokens_part) = line.strip_prefix("Generation:")
108→                    && let Some(tokens_str) = tokens_part.split_whitespace().next()
109→                {
110→                    output_tokens = tokens_str.parse().ok();
111→                }
112→            }
113→        }
114→
115→        ParsedResponse {
116→            text,
117→            input_tokens,
118→            output_tokens,
119→        }
120→    }
121→}
122→
123→// ── Passthrough Parser ───────────────────────────────────────────────────────
124→
125→/// Parser that returns raw output unchanged.
126→///
127→/// Useful as a fallback or for outputs that don't need cleaning.
128→#[derive(Debug, Default)]
129→pub struct PassthroughParser;
130→
131→impl ResponseParser for PassthroughParser {
132→    fn name(&self) -> &'static str {
133→        "passthrough"
134→    }
135→
136→    fn parse(&self, raw: &str) -> ParsedResponse {
137→        ParsedResponse {
138→            text: raw.to_string(),
139→            input_tokens: None,
140→            output_tokens: None,
141→        }
142→    }
143→}
