1001→        fn stream<'a>(
1002→            &'a self,
1003→            messages: &'a [ChatMessage],
1004→        ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + 'a>> {
1005→            let prompt = format_messages(messages, self.chat_template());
1006→            let model_path = self.model_path.to_string_lossy().to_string();
1007→            let temperature = self.temperature;
1008→            let installation = self.installation;
1009→
1010→            Box::pin(async_stream::stream! {
1011→                // Use spawn_blocking for the streaming generation
1012→                let (tx, mut rx) = tokio::sync::mpsc::channel::<StreamEvent>(32);
1013→
1014→                let handle = tokio::task::spawn_blocking(move || {
1015→                    stream_generate_mlx(&model_path, &prompt, 4096, temperature, installation, tx)
1016→                });
1017→
1018→                while let Some(event) = rx.recv().await {
1019→                    let is_done = matches!(event, StreamEvent::Done(_) | StreamEvent::Error(_));
1020→                    yield event;
1021→                    if is_done {
1022→                        break;
1023→                    }
1024→                }
1025→
1026→                if let Err(e) = handle.await {
1027→                    warn!("MLX generation task error: {e}");
1028→                }
1029→            })
1030→        }
1031→    }
