1033→    /// Streaming generation using mlx-lm.
1034→    fn stream_generate_mlx(
1035→        model_path: &str,
1036→        prompt: &str,
1037→        max_tokens: u32,
1038→        temperature: f32,
1039→        installation: super::MlxInstallation,
1040→        tx: tokio::sync::mpsc::Sender<StreamEvent>,
1041→    ) {
1042→        let result = match installation {
1043→            super::MlxInstallation::PythonPackage => {
1044→                stream_generate_python(model_path, prompt, max_tokens, temperature, &tx)
1045→            },
1046→            super::MlxInstallation::HomebrewCli => {
1047→                stream_generate_cli(model_path, prompt, max_tokens, temperature, &tx)
1048→            },
1049→        };
1050→
1051→        match result {
1052→            Ok((input_tokens, output_tokens)) => {
1053→                let _ = tx.blocking_send(StreamEvent::Done(Usage {
1054→                    input_tokens,
1055→                    output_tokens,
1056→                    ..Default::default()
1057→                }));
1058→            },
1059→            Err(e) => {
1060→                let _ = tx.blocking_send(StreamEvent::Error(e.to_string()));
1061→            },
1062→        }
1063→    }
1064→
1065→    /// Streaming generation using mlx-lm Python package.
1066→    fn stream_generate_python(
1067→        model_path: &str,
1068→        prompt: &str,
1069→        max_tokens: u32,
1070→        temperature: f32,
1071→        tx: &tokio::sync::mpsc::Sender<StreamEvent>,
1072→    ) -> Result<(u32, u32)> {
1073→        let script = format!(
1074→            r#"
1075→import mlx_lm
1076→from mlx_lm.sample_utils import make_sampler
1077→import sys
1078→
1079→model, tokenizer = mlx_lm.load("{model_path}")
1080→prompt = {prompt_json}
1081→sampler = make_sampler(temp={temperature})
1082→
1083→input_tokens = len(tokenizer.encode(prompt))
1084→output_tokens = 0
1085→
1086→for token in mlx_lm.stream_generate(
1087→    model,
1088→    tokenizer,
1089→    prompt=prompt,
1090→    max_tokens={max_tokens},
1091→    sampler=sampler,
1092→):
1093→    output_tokens += 1
1094→    print(token, end="", flush=True)
1095→
1096→print(f"\n__TOKENS__:{{input_tokens}}:{{output_tokens}}", flush=True)
1097→"#,
1098→            model_path = model_path,
1099→            prompt_json = serde_json::to_string(&prompt).unwrap_or_default(),
1100→            max_tokens = max_tokens,
1101→            temperature = temperature,
1102→        );
1103→
1104→        let mut child = Command::new("python3")
1105→            .args(["-c", &script])
1106→            .stdout(Stdio::piped())
1107→            .stderr(Stdio::piped())
1108→            .spawn()
1109→            .context("failed to spawn mlx-lm")?;
1110→
1111→        let stdout = child.stdout.take().context("no stdout")?;
1112→        let reader = BufReader::new(stdout);
1113→
1114→        let mut input_tokens = 0u32;
1115→        let mut output_tokens = 0u32;
1116→
1117→        // Read lines from the process output
1118→        for line in reader.lines() {
1119→            let line = line.context("failed to read line")?;
1120→
1121→            if line.starts_with("__TOKENS__:") {
1122→                // Parse token counts
1123→                let parts: Vec<&str> = line.split(':').collect();
1124→                if parts.len() >= 3 {
1125→                    input_tokens = parts[1].parse().unwrap_or(0);
1126→                    output_tokens = parts[2].parse().unwrap_or(0);
1127→                }
1128→            } else {
1129→                // Send as delta
1130→                if tx.blocking_send(StreamEvent::Delta(line)).is_err() {
1131→                    break;
1132→                }
1133→            }
1134→        }
1135→
1136→        let status = child.wait().context("failed to wait for mlx-lm")?;
1137→        if !status.success() {
1138→            bail!("mlx-lm (Python) exited with error");
1139→        }
1140→
1141→        Ok((input_tokens, output_tokens))
1142→    }
1143→
1144→    /// Streaming generation using mlx-lm CLI (Homebrew).
1145→    ///
1146→    /// Note: The CLI doesn't support true streaming output, so we collect all
1147→    /// output, parse it with the response parser, and send the cleaned text.
1148→    fn stream_generate_cli(
1149→        model_path: &str,
1150→        prompt: &str,
1151→        max_tokens: u32,
1152→        temperature: f32,
1153→        tx: &tokio::sync::mpsc::Sender<StreamEvent>,
1154→    ) -> Result<(u32, u32)> {
1155→        // Use the non-streaming generate function which already uses the parser
1156→        let (text, input_tokens, output_tokens) =
1157→            generate_with_cli(model_path, prompt, max_tokens, temperature)?;
1158→
1159→        // Send the parsed text as a single delta
1160→        let _ = tx.blocking_send(StreamEvent::Delta(text));
1161→
1162→        Ok((input_tokens, output_tokens))
1163→    }
1164→
1165→    /// Resolve an MLX model, downloading it if necessary.
1166→    ///
1167→    /// Checks both the unified and legacy registries, downloads the model
1168→    /// to the local cache, and returns the path to the model directory.
1169→    async fn resolve_mlx_model(
1170→        config: &LocalLlmConfig,
1171→    ) -> Result<(PathBuf, Option<&'static LocalModelDef>, u32)> {
1172→        // If a custom path is provided, use it directly (if it exists)
1173→        if let Some(path) = &config.model_path {
1174→            if path.exists() {
1175→                info!(
1176→                    path = %path.display(),
1177→                    "using custom MLX model path"
1178→                );
1179→                let model_def = models::find_model(&config.model_id);
1180→                let context_size = config
1181→                    .context_size
1182→                    .or_else(|| model_def.map(|d| d.context_window))
1183→                    .unwrap_or(8192);
1184→                return Ok((path.clone(), model_def, context_size));
1185→            } else {
1186→                bail!("model path not found: {}", path.display());
1187→            }
1188→        }
1189→
1190→        // First, check the unified registry
1191→        if let Some(def) = models::find_model(&config.model_id)
1192→            && def.has_mlx()
1193→        {
1194→            info!(
1195→                model = config.model_id,
1196→                mlx_repo = ?def.mlx_repo,
1197→                "found model in unified registry, downloading"
1198→            );
1199→            let model_path = models::ensure_mlx_model(def, &config.cache_dir).await?;
1200→            let context_size = config.context_size.unwrap_or(def.context_window);
1201→            return Ok((model_path, Some(def), context_size));
1202→        }
1203→
1204→        // Check the legacy registry (for models like mlx-qwen2.5-coder-1.5b-4bit)
1205→        if let Some(legacy_def) = crate::local_gguf::models::find_model(&config.model_id)
1206→            && legacy_def.backend == crate::local_gguf::models::ModelBackend::Mlx
1207→        {
1208→            info!(
1209→                model = config.model_id,
1210→                hf_repo = legacy_def.hf_repo,
1211→                "found model in legacy registry, downloading"
1212→            );
1213→            let model_path =
1214→                crate::local_gguf::models::ensure_mlx_model(legacy_def, &config.cache_dir).await?;
1215→            let context_size = config.context_size.unwrap_or(legacy_def.context_window);
1216→            return Ok((model_path, None, context_size));
1217→        }
1218→
1219→        // If the model ID looks like a HuggingFace repo, download it directly
1220→        if models::is_hf_repo_id(&config.model_id) {
1221→            info!(
1222→                model = config.model_id,
1223→                "downloading custom MLX model from HuggingFace repo"
1224→            );
1225→            let model_path = models::ensure_mlx_repo(&config.model_id, &config.cache_dir).await?;
1226→            let context_size = config.context_size.unwrap_or(8192);
1227→            return Ok((model_path, None, context_size));
1228→        }
1229→
1230→        bail!(
1231→            "unknown MLX model '{}'. Use a HuggingFace repo ID (e.g. mlx-community/Model-Name) or model_path for custom MLX models.",
1232→            config.model_id
1233→        );
1234→    }
1235→}
