 24→/// Types of local LLM backends.
 25→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
 26→pub enum BackendType {
 27→    /// GGUF format via llama.cpp - cross-platform
 28→    Gguf,
