 59→/// Trait for local LLM inference backends.
 60→#[async_trait]
 61→pub trait LocalBackend: Send + Sync {
 62→    /// Get the backend type.
 63→    fn backend_type(&self) -> BackendType;
 64→
 65→    /// Get the model ID.
 66→    fn model_id(&self) -> &str;
 67→
 68→    /// Get the context window size.
 69→    fn context_window(&self) -> u32;
 70→
 71→    /// Whether this backend supports grammar-constrained tool calling.
 72→    fn supports_tools(&self) -> bool {
 73→        false
 74→    }
 75→
 76→    /// Run completion (non-streaming).
 77→    async fn complete(&self, messages: &[ChatMessage]) -> Result<CompletionResponse>;
 78→
 79→    /// Run completion with tool schemas for grammar-constrained generation.
 80→    async fn complete_with_tools(
 81→        &self,
 82→        messages: &[ChatMessage],
 83→        _tools: &[serde_json::Value],
 84→    ) -> Result<CompletionResponse> {
 85→        self.complete(messages).await
 86→    }
