 95→/// Detect the best backend for the current system (ignoring model type).
 96→#[must_use]
 97→pub fn detect_best_backend() -> BackendType {
 98→    let sys = super::system_info::SystemInfo::detect();
 99→
100→    // On Apple Silicon, prefer MLX if available
101→    if sys.is_apple_silicon && is_mlx_available() {
102→        return BackendType::Mlx;
103→    }
104→
105→    // Default to GGUF (always available when compiled with local-llm feature)
106→    BackendType::Gguf
107→}
108→
109→/// Detect the best backend for a specific model.
110→///
111→/// This checks:
112→/// 1. Legacy MLX models (mlx-* prefix) -> requires MLX backend
113→/// 2. Unified registry models with MLX support -> prefers MLX on Apple Silicon
114→/// 3. GGUF-only models -> uses GGUF backend
115→/// 4. Unknown models -> falls back to system detection
116→#[must_use]
117→pub fn detect_backend_for_model(model_id: &str) -> BackendType {
118→    // Check legacy MLX models first (from local_gguf registry)
119→    if let Some(def) = crate::local_gguf::models::find_model(model_id) {
120→        if matches!(def.backend, crate::local_gguf::models::ModelBackend::Mlx) {
121→            // MLX model from legacy registry - requires MLX backend
122→            if is_mlx_available() {
123→                return BackendType::Mlx;
124→            } else {
125→                // MLX not available but model requires it - log warning, return Mlx anyway
126→                // (will fail with a clear error when loading)
127→                tracing::warn!(
128→                    model = model_id,
129→                    "MLX model selected but MLX backend not available"
130→                );
131→                return BackendType::Mlx;
132→            }
133→        }
134→        // GGUF model from legacy registry
135→        return BackendType::Gguf;
136→    }
137→
138→    // Check unified registry
139→    if let Some(def) = super::models::find_model(model_id) {
140→        // If model has MLX support and MLX is available, prefer MLX
141→        if def.has_mlx() && is_mlx_available() {
142→            return BackendType::Mlx;
143→        }
144→        // Otherwise use GGUF
145→        return BackendType::Gguf;
146→    }
147→
148→    // If the model ID looks like a HuggingFace repo, treat it as an MLX model
149→    // when MLX is available (e.g. "mlx-community/Qwen3.5-4B-MLX-4bit").
150→    if super::models::is_hf_repo_id(model_id) && is_mlx_available() {
151→        return BackendType::Mlx;
152→    }
153→
154→    // Unknown model - fall back to system detection
155→    detect_best_backend()
156→}
