158→/// Get list of available backends on this system.
159→#[must_use]
160→pub fn available_backends() -> Vec<BackendType> {
161→    let mut backends = vec![BackendType::Gguf]; // Always available
162→
163→    if cfg!(target_os = "macos") && cfg!(target_arch = "aarch64") && is_mlx_available() {
164→        backends.push(BackendType::Mlx);
165→    }
166→
167→    backends
168→}
