170→/// How mlx-lm is installed on this system.
171→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
172→pub enum MlxInstallation {
173→    /// Installed as a Python package (pip install mlx-lm)
174→    PythonPackage,
175→    /// Installed as a standalone command (brew install mlx-lm)
176→    HomebrewCli,
177→}
178→
179→/// Detect how mlx-lm is installed, if at all.
180→#[must_use]
181→pub fn detect_mlx_installation() -> Option<MlxInstallation> {
182→    // Check if we're on Apple Silicon macOS
183→    if !(cfg!(target_os = "macos") && cfg!(target_arch = "aarch64")) {
184→        return None;
185→    }
186→
187→    // Method 1: Check if mlx_lm can be imported in Python (pip install)
188→    let python_available = std::process::Command::new("python3")
189→        .args(["-c", "import mlx_lm"])
190→        .stdout(std::process::Stdio::null())
191→        .stderr(std::process::Stdio::null())
192→        .status()
193→        .map(|s| s.success())
194→        .unwrap_or(false);
195→
196→    if python_available {
197→        return Some(MlxInstallation::PythonPackage);
198→    }
199→
200→    // Method 2: Check if mlx_lm command exists (Homebrew installation)

200→    // Method 2: Check if mlx_lm command exists (Homebrew installation)
201→    let cli_available = std::process::Command::new("which")
202→        .arg("mlx_lm")
203→        .stdout(std::process::Stdio::null())
204→        .stderr(std::process::Stdio::null())
205→        .status()
206→        .map(|s| s.success())
207→        .unwrap_or(false);
208→
209→    if cli_available {
210→        return Some(MlxInstallation::HomebrewCli);
211→    }
212→
213→    None
214→}
