222→/// Create a backend instance for the given type and config.
223→pub async fn create_backend(
224→    backend_type: BackendType,
225→    config: &LocalLlmConfig,
226→) -> Result<Box<dyn LocalBackend>> {
227→    match backend_type {
228→        BackendType::Gguf => {
229→            let backend = gguf::GgufBackend::from_config(config).await?;
230→            Ok(Box::new(backend))
231→        },
232→        BackendType::Mlx => {
233→            let backend = mlx::MlxBackend::from_config(config).await?;
234→            Ok(Box::new(backend))
