241→pub mod gguf {
242→    //! GGUF backend using llama-cpp-2.
243→
244→    use std::{num::NonZeroU32, pin::Pin, sync::Arc};
245→
246→    use {
247→        anyhow::{Context, Result, bail},
248→        async_trait::async_trait,
249→        llama_cpp_2::{
250→            context::params::LlamaContextParams,
251→            llama_backend::LlamaBackend,
252→            llama_batch::LlamaBatch,
253→            model::{LlamaModel, params::LlamaModelParams},
254→            sampling::LlamaSampler,
255→            token::LlamaToken,
256→        },
257→        tokio::sync::Mutex,
258→        tokio_stream::Stream,
259→        tracing::{debug, info, warn},
260→    };
261→
262→    use moltis_agents::model::{ChatMessage, CompletionResponse, StreamEvent, ToolCall, Usage};
263→
264→    use {
265→        super::{BackendType, LocalBackend, LocalLlmConfig},
266→        crate::local_llm::models::{
267→            self, LocalModelDef,
268→            chat_templates::{ChatTemplateHint, format_messages},
269→        },
270→    };
271→
272→    use crate::local_gguf::tool_grammar;
273→
274→    /// Wrapper around `LlamaBackend` that opts into `Send + Sync`.
275→    struct SendSyncBackend(LlamaBackend);
276→
277→    // SAFETY: LlamaBackend is an immutable init handle with no thread-local state.
278→    #[allow(unsafe_code)]
279→    unsafe impl Send for SendSyncBackend {}
280→    #[allow(unsafe_code)]
281→    unsafe impl Sync for SendSyncBackend {}
282→
283→    /// GGUF backend implementation.
284→    struct GgufModelHandle {
285→        model: Mutex<LlamaModel>,
286→        model_size_bytes: u64,
287→    }
288→
289→    impl GgufModelHandle {
290→        fn new(model: LlamaModel) -> Self {
291→            let model_size_bytes = model.size();
292→            super::LOADED_LLAMA_MODEL_BYTES
293→                .fetch_add(model_size_bytes, std::sync::atomic::Ordering::Relaxed);
294→            Self {
295→                model: Mutex::new(model),
296→                model_size_bytes,
297→            }
298→        }
299→    }
300→
301→    impl Drop for GgufModelHandle {
302→        fn drop(&mut self) {
303→            super::LOADED_LLAMA_MODEL_BYTES
304→                .fetch_sub(self.model_size_bytes, std::sync::atomic::Ordering::Relaxed);
305→        }
306→    }
307→
308→    pub struct GgufBackend {
309→        backend: Arc<SendSyncBackend>,
310→        model: Arc<GgufModelHandle>,
311→        model_id: String,
312→        model_def: Option<&'static LocalModelDef>,
313→        context_size: u32,
314→        temperature: f32,
315→    }
316→
317→    impl GgufBackend {
318→        /// Load a GGUF backend from configuration.
319→        pub async fn from_config(config: &LocalLlmConfig) -> Result<Self> {
320→            // Resolve model path
321→            let (model_path, model_def) = if let Some(path) = &config.model_path {
322→                if !path.exists() {
323→                    bail!("model file not found: {}", path.display());
324→                }
325→                (path.clone(), models::find_model(&config.model_id))
326→            } else {
327→                let Some(def) = models::find_model(&config.model_id) else {
328→                    bail!(
329→                        "unknown model '{}'. Use model_path for custom GGUF files.",
330→                        config.model_id
331→                    );
332→                };
333→                let path = models::ensure_model(def, &config.cache_dir).await?;
334→                (path, Some(def))
335→            };
336→
337→            // Determine context size
338→            let context_size = config
339→                .context_size
340→                .or_else(|| model_def.map(|d| d.context_window))
341→                .unwrap_or(8192);
342→
343→            // Load the model
344→            let backend = LlamaBackend::init().context("initializing llama backend")?;
345→
346→            let mut model_params = LlamaModelParams::default();
347→
348→            if config.gpu_layers > 0 {
349→                model_params = model_params.with_n_gpu_layers(config.gpu_layers);
350→                info!(gpu_layers = config.gpu_layers, "GPU offloading enabled");
351→            }
352→
353→            let model = LlamaModel::load_from_file(&backend, &model_path, &model_params)
354→                .map_err(|e| anyhow::anyhow!("failed to load GGUF model: {e}"))?;
355→            let model_handle = Arc::new(GgufModelHandle::new(model));
356→
357→            info!(
358→                path = %model_path.display(),
359→                model = %config.model_id,
360→                context_size,
361→                model_size_bytes = model_handle.model_size_bytes,
362→                "loaded GGUF model"
363→            );
364→
365→            Ok(Self {
366→                backend: Arc::new(SendSyncBackend(backend)),
367→                model: model_handle,
368→                model_id: config.model_id.clone(),
369→                model_def,
370→                context_size,
371→                temperature: config.temperature,
372→            })
373→        }
374→
375→        /// Get the chat template hint for this model.
376→        fn chat_template(&self) -> ChatTemplateHint {
377→            self.model_def
378→                .and_then(|d| d.chat_template)
379→                .unwrap_or(ChatTemplateHint::Auto)
380→        }
381→
382→        /// Generate text synchronously.
383→        ///
384→        /// When `tool_names` is non-empty, a lazy GBNF grammar sampler constrains
385→        /// the output to valid `tool_call` fenced blocks.
386→        fn generate_sync(
387→            &self,
388→            prompt: &str,
389→            max_tokens: u32,
390→            tool_names: &[&str],
391→        ) -> Result<(String, u32, u32)> {
392→            let model = self.model.model.blocking_lock();
393→            let backend = &self.backend.0;
394→
395→            let batch_size: usize = 512;
396→
397→            let ctx_params = LlamaContextParams::default()
398→                .with_n_ctx(NonZeroU32::new(self.context_size))
399→                .with_n_batch(batch_size as u32);
400→            let mut ctx = model
401→                .new_context(backend, ctx_params)
402→                .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
403→
404→            let tokens = model
405→                .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
406→                .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
407→
408→            let input_tokens = tokens.len() as u32;
409→            debug!(input_tokens, batch_size, "tokenized prompt");
410→
411→            if tokens.is_empty() {
412→                bail!("empty token sequence");
413→            }
414→
415→            // Process prompt in batches
416→            let mut batch = LlamaBatch::new(batch_size, 1);
417→            for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
418→                batch.clear();
419→                let chunk_start = chunk_idx * batch_size;
420→                let is_last_chunk = chunk_start + chunk.len() == tokens.len();
421→
422→                for (i, &token) in chunk.iter().enumerate() {
423→                    let pos = (chunk_start + i) as i32;
424→                    let is_last = is_last_chunk && i == chunk.len() - 1;
425→                    batch
426→                        .add(token, pos, &[0], is_last)
427→                        .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
428→                }
429→
430→                ctx.decode(&mut batch)
431→                    .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
432→            }
433→
434→            // Set up sampler chain with optional grammar constraint.
435→            let mut samplers: Vec<LlamaSampler> = Vec::new();
436→
437→            if let Some(grammar_str) = tool_grammar::build_tool_call_grammar(tool_names) {
438→                match LlamaSampler::grammar_lazy(&model, &grammar_str, "root", ["```tool_call"], &[
439→                ]) {
440→                    Ok(grammar_sampler) => {
441→                        debug!("grammar-constrained sampling enabled for tool calls");
442→                        samplers.push(grammar_sampler);
443→                    },
444→                    Err(e) => {
445→                        warn!(%e, "failed to create grammar sampler, falling back to unconstrained");
446→                    },
447→                }
448→            }
449→
450→            samplers.push(LlamaSampler::temp(self.temperature));
451→            samplers.push(LlamaSampler::dist(42));
452→
453→            let mut sampler = LlamaSampler::chain_simple(samplers);
454→
455→            let mut output_tokens = Vec::new();
456→            let mut pos = tokens.len() as i32;
457→            let eos_token = model.token_eos();
458→
459→            for _ in 0..max_tokens {
460→                let token = sampler.sample(&ctx, batch.n_tokens() - 1);
461→
462→                if token == eos_token {
463→                    debug!("reached EOS token");
464→                    break;
465→                }
466→
467→                output_tokens.push(token);
468→                sampler.accept(token);
469→
470→                batch.clear();
471→                batch
472→                    .add(token, pos, &[0], true)
473→                    .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
474→                ctx.decode(&mut batch)
475→                    .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
476→
477→                pos += 1;
478→            }
479→
480→            let output_text = detokenize(&model, &output_tokens)?;
481→
482→            Ok((output_text, input_tokens, output_tokens.len() as u32))
483→        }
484→    }
