486→    /// Detokenize a sequence of tokens into a string.
487→    fn detokenize(model: &LlamaModel, tokens: &[LlamaToken]) -> Result<String> {
488→        let mut decoder = encoding_rs::UTF_8.new_decoder();
489→        let mut output = String::new();
490→        for &token in tokens {
491→            let piece = model
492→                .token_to_piece(token, &mut decoder, true, None)
493→                .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
494→            output.push_str(&piece);
495→        }
496→        Ok(output)
497→    }
