628→    /// Streaming generation in a blocking context.
629→    fn stream_generate_sync(
630→        backend: &LlamaBackend,
631→        model: &GgufModelHandle,
632→        prompt: &str,
633→        max_tokens: u32,
634→        context_size: u32,
635→        temperature: f32,
636→        tx: tokio::sync::mpsc::Sender<StreamEvent>,
637→    ) {
638→        let batch_size: usize = 512;
639→
640→        let result = (|| -> Result<(u32, u32)> {
641→            let model = model.model.blocking_lock();
642→
643→            let ctx_params = LlamaContextParams::default()
644→                .with_n_ctx(NonZeroU32::new(context_size))
645→                .with_n_batch(batch_size as u32);
646→            let mut ctx = model
647→                .new_context(backend, ctx_params)
648→                .map_err(|e| anyhow::anyhow!("failed to create llama context: {e}"))?;
649→
650→            let tokens = model
651→                .str_to_token(prompt, llama_cpp_2::model::AddBos::Always)
652→                .map_err(|e| anyhow::anyhow!("tokenization failed: {e}"))?;
653→
654→            let input_tokens = tokens.len() as u32;
655→
656→            if tokens.is_empty() {
657→                bail!("empty token sequence");
658→            }
659→
660→            // Process prompt in batches
661→            let mut batch = LlamaBatch::new(batch_size, 1);
662→            for (chunk_idx, chunk) in tokens.chunks(batch_size).enumerate() {
663→                batch.clear();
664→                let chunk_start = chunk_idx * batch_size;
665→                let is_last_chunk = chunk_start + chunk.len() == tokens.len();
666→
667→                for (i, &token) in chunk.iter().enumerate() {
668→                    let pos = (chunk_start + i) as i32;
669→                    let is_last = is_last_chunk && i == chunk.len() - 1;
670→                    batch
671→                        .add(token, pos, &[0], is_last)
672→                        .map_err(|e| anyhow::anyhow!("batch add failed: {e}"))?;
673→                }
674→
675→                ctx.decode(&mut batch)
676→                    .map_err(|e| anyhow::anyhow!("prompt decode failed: {e}"))?;
677→            }
678→
679→            let mut sampler = LlamaSampler::chain_simple([
680→                LlamaSampler::temp(temperature),
681→                LlamaSampler::dist(42),
682→            ]);
683→
684→            let mut output_tokens = 0u32;
685→            let mut pos = tokens.len() as i32;
686→            let eos_token = model.token_eos();
687→            let mut decoder = encoding_rs::UTF_8.new_decoder();
688→
689→            for _ in 0..max_tokens {
690→                let token = sampler.sample(&ctx, batch.n_tokens() - 1);
691→
692→                if token == eos_token {
693→                    break;
694→                }
695→
696→                output_tokens += 1;
697→                sampler.accept(token);
698→
699→                let piece = model
700→                    .token_to_piece(token, &mut decoder, true, None)
701→                    .map_err(|e| anyhow::anyhow!("detokenization failed: {e}"))?;
702→
703→                if tx.blocking_send(StreamEvent::Delta(piece)).is_err() {
704→                    break;
705→                }
706→
707→                batch.clear();
708→                batch
709→                    .add(token, pos, &[0], true)
710→                    .map_err(|e| anyhow::anyhow!("batch add token failed: {e}"))?;
711→                ctx.decode(&mut batch)
712→                    .map_err(|e| anyhow::anyhow!("token decode failed: {e}"))?;
713→
714→                pos += 1;
715→            }
716→
717→            Ok((input_tokens, output_tokens))
718→        })();
719→
720→        match result {
721→            Ok((input_tokens, output_tokens)) => {
722→                let _ = tx.blocking_send(StreamEvent::Done(Usage {
723→                    input_tokens,
724→                    output_tokens,
725→                    ..Default::default()
726→                }));
727→            },
728→            Err(e) => {
729→                let _ = tx.blocking_send(StreamEvent::Error(e.to_string()));
730→            },
731→        }
732→    }
733→}
