 907→    /// Strip common chat template stop tokens from model output.
 908→    fn strip_chat_template_tokens(text: &str) -> String {
 909→        // Common stop tokens from various chat templates
 910→        const STOP_TOKENS: &[&str] = &[
 911→            "<|im_end|>",    // ChatML (Qwen, Yi, etc.)
 912→            "<|eot_id|>",    // Llama 3
 913→            "</s>",          // Llama 2, Mistral
 914→            "<|end|>",       // Phi
 915→            "<|endoftext|>", // GPT-2 style
 916→        ];
 917→
 918→        let mut result = text.to_string();
 919→        for token in STOP_TOKENS {
 920→            // Strip from end (most common case)
 921→            if result.ends_with(token) {
 922→                result = result[..result.len() - token.len()].to_string();
 923→            }
 924→            // Also handle if it appears mid-response (model continued after stop)
 925→            if let Some(pos) = result.find(token) {
 926→                result = result[..pos].to_string();
 927→            }
 928→        }
 929→        result.trim_end().to_string()
 930→    }
