 932→    /// Generate text using mlx-lm CLI (Homebrew installation).
 933→    fn generate_with_cli(
 934→        model_path: &str,
 935→        prompt: &str,
 936→        max_tokens: u32,
 937→        temperature: f32,
 938→    ) -> Result<(String, u32, u32)> {
 939→        use crate::local_llm::response_parser::{MlxCliResponseParser, ResponseParser};
 940→
 941→        // mlx_lm generate --model <model> --prompt <prompt> --max-tokens <N> --temp <T>
 942→        let output = Command::new("mlx_lm")
 943→            .arg("generate")
 944→            .args(["--model", model_path])
 945→            .args(["--prompt", prompt])
 946→            .args(["--max-tokens", &max_tokens.to_string()])
 947→            .args(["--temp", &temperature.to_string()])
 948→            .output()
 949→            .context("failed to run mlx_lm CLI")?;
 950→
 951→        if !output.status.success() {
 952→            let stderr = String::from_utf8_lossy(&output.stderr);
 953→            bail!("mlx_lm CLI failed: {}", stderr);
 954→        }
 955→
 956→        let raw_output = String::from_utf8_lossy(&output.stdout);
 957→
 958→        // Use the MlxCliResponseParser to parse the decorated output
 959→        let parser = MlxCliResponseParser;
 960→        let parsed = parser.parse(&raw_output);
 961→
 962→        // Strip chat template stop tokens from the response
 963→        let text = strip_chat_template_tokens(&parsed.text);
 964→
 965→        // Fallback to estimation if parser didn't get token counts
 966→        let input_tokens = parsed.input_tokens.unwrap_or((prompt.len() / 4) as u32);
 967→        let output_tokens = parsed.output_tokens.unwrap_or((text.len() / 4) as u32);
 968→
 969→        Ok((text, input_tokens, output_tokens))
 970→    }
