1033→    /// Streaming generation using mlx-lm.
1034→    fn stream_generate_mlx(
1035→        model_path: &str,
1036→        prompt: &str,
1037→        max_tokens: u32,
1038→        temperature: f32,
1039→        installation: super::MlxInstallation,
1040→        tx: tokio::sync::mpsc::Sender<StreamEvent>,
1041→    ) {
1042→        let result = match installation {
1043→            super::MlxInstallation::PythonPackage => {
1044→                stream_generate_python(model_path, prompt, max_tokens, temperature, &tx)
1045→            },
1046→            super::MlxInstallation::HomebrewCli => {
1047→                stream_generate_cli(model_path, prompt, max_tokens, temperature, &tx)
1048→            },
1049→        };
1050→
1051→        match result {
1052→            Ok((input_tokens, output_tokens)) => {
1053→                let _ = tx.blocking_send(StreamEvent::Done(Usage {
1054→                    input_tokens,
1055→                    output_tokens,
1056→                    ..Default::default()
1057→                }));
1058→            },
1059→            Err(e) => {
1060→                let _ = tx.blocking_send(StreamEvent::Error(e.to_string()));
1061→            },
1062→        }
1063→    }
