104→    /// Convert to OpenAI-compatible JSON format.
105→    ///
106→    /// Used by providers that speak the OpenAI Chat Completions API:
107→    /// OpenAI, Mistral, Copilot, Kimi, Cerebras, etc.
108→    #[must_use]
109→    pub fn to_openai_value(&self) -> serde_json::Value {
110→        match self {
111→            ChatMessage::System { content } => {
112→                serde_json::json!({ "role": "system", "content": content })
113→            },
114→            ChatMessage::User { content } => match content {
115→                UserContent::Text(text) => {
116→                    serde_json::json!({ "role": "user", "content": text })
117→                },
118→                UserContent::Multimodal(parts) => {
119→                    let blocks: Vec<serde_json::Value> = parts
120→                        .iter()
121→                        .map(|part| match part {
122→                            ContentPart::Text(text) => {
123→                                serde_json::json!({ "type": "text", "text": text })
124→                            },
125→                            ContentPart::Image { media_type, data } => {
126→                                let data_uri = format!("data:{media_type};base64,{data}");
127→                                serde_json::json!({
128→                                    "type": "image_url",
129→                                    "image_url": { "url": data_uri }
130→                                })
131→                            },
132→                        })
133→                        .collect();
134→                    serde_json::json!({ "role": "user", "content": blocks })
135→                },
136→            },
137→            ChatMessage::Assistant {
138→                content,
139→                tool_calls,
140→            } => {
141→                if tool_calls.is_empty() {
142→                    serde_json::json!({
143→                        "role": "assistant",
144→                        "content": content.as_deref().unwrap_or(""),
145→                    })
146→                } else {
147→                    let tc_json: Vec<serde_json::Value> = tool_calls
148→                        .iter()
149→                        .map(|tc| {
150→                            serde_json::json!({
151→                                "id": tc.id,
152→                                "type": "function",
153→                                "function": {
154→                                    "name": tc.name,
155→                                    "arguments": tc.arguments.to_string(),
156→                                }
157→                            })
158→                        })
159→                        .collect();
160→                    let mut msg = serde_json::json!({
161→                        "role": "assistant",
162→                        "tool_calls": tc_json,
163→                    });
164→                    if let Some(text) = content {
165→                        msg["content"] = serde_json::Value::String(text.clone());
166→                    }
167→                    msg
168→                }
169→            },
170→            ChatMessage::Tool {
171→                tool_call_id,
172→                content,
173→            } => {
174→                serde_json::json!({
175→                    "role": "tool",
176→                    "tool_call_id": tool_call_id,
177→                    "content": content,
178→                })
179→            },
180→        }
181→    }
182→}
